const fs=require("fs"),path=require("path"),{google:google}=require("googleapis"),CHANNEL_HANDLE="@Bacarotech",OUTPUT_DIR=path.join(__dirname,"..","content","blog");function getApiKey(){let e=process.env.YOUTUBE_API_KEY;if(!e){const t=path.join(__dirname,"..",".env");if(fs.existsSync(t)){const o=fs.readFileSync(t,"utf-8").match(/YOUTUBE_API_KEY=(.+)/);o&&(e=o[1].trim())}}return e||(console.error("ERRORE: YouTube API Key non trovata!"),console.error("Imposta la variabile d'ambiente YOUTUBE_API_KEY o crea un file .env"),console.error(""),console.error("Per ottenere una chiave API:"),console.error("1. Vai su https://console.cloud.google.com/"),console.error("2. Crea un progetto"),console.error("3. Abilita YouTube Data API v3"),console.error("4. Crea le credenziali (API Key)"),process.exit(1)),e}async function getChannelInfo(e,t){console.log(`Cercando canale con handle: ${t}`);try{const o=await e.channels.list({forHandle:t,part:"id,snippet,contentDetails"});if(console.log("Response status:",o.status),o.data&&o.data.items&&console.log("Numero di canali trovati:",o.data.items.length),o.data.items&&o.data.items.length>0){const e=o.data.items[0];return{id:e.id,uploadsPlaylistId:e.contentDetails.relatedPlaylists.uploads}}return null}catch(e){throw console.error("Errore nel recupero del canale:",e.message),e}}function parseDuration(e){if(!e)return 0;const t=e.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);if(!t)return 0;return 3600*parseInt(t[1]||0)+60*parseInt(t[2]||0)+parseInt(t[3]||0)}function isShort(e){return parseDuration(e)<=60}function extractSeries(e){let t=e.replace(/^([A-Za-z0-9\s]+?)\s*-\s*\1\s*-\s*/i,"$1 - ");const o=[/^([A-Za-z0-9]+(?:\s+[A-Za-z0-9]+)*?)\s+EP\s*\d+/i,/^([A-Za-z0-9]+(?:\s+[A-Za-z0-9]+)*?)\s*#\s*\d+/i,/^([A-Za-z0-9]+(?:\s+[A-Za-z0-9]+)*?)\s+PT\s*\d+/i,/^([A-Za-z0-9]+(?:\s+[A-Za-z0-9]+)*?)\s+-\s+[A-Za-z]/i,/^([A-Za-z0-9]+(?:\s+[A-Za-z0-9]+)*?):\s+/i];for(const e of o){const o=t.match(e);if(o){let e=o[1].trim();return e=e.replace(/\s+/g," "),e}}return null}function generateSlug(e){let t=e.toLowerCase();return t=t.replace(/[^a-z0-9\s-]/g,""),t=t.replace(/\s+/g,"-"),t=t.replace(/-+/g,"-"),t.substring(0,100)}function generateFrontmatter(e,t,o){const n=e.snippet.publishedAt,s=new Date(n).getFullYear(),a=[];t?a.push("short"):a.push("video");const r=e.snippet.tags||[];for(const e of r.slice(0,10)){const t=e.toLowerCase().replace(/\s+/g,"-");a.includes(t)||a.push(t)}let i=`---\ntitle: "${e.snippet.title.replace(/"/g,'\\"')}"\ndate: ${n}\nfeatured: false\nweight: 100\ndescription: "${(e.snippet.description||"").substring(0,200).replace(/"/g,'\\"')}"\ntags:\n`;for(const e of a)i+=` - "${e}"\n`;return i+="topics:\nauthors:\n",i+=o?`series:\n - "${o}"\n`:"series:\n",i+="---\n\n",{frontmatter:i,year:s}}function generateContent(e,t){let o=e.snippet.description||"";const n=e.id;return o+=`\n\n{{< youtube ${n} >}}\n`,o}async function getAllVideos(e,t){const o=[];let n=null;console.log("Recupero i video dalla playlist uploads...",t);try{do{const s=await e.playlistItems.list({playlistId:t,part:"snippet",maxResults:50,pageToken:n});if(console.log("Playlist response status:",s.status),console.log("Numero di risultati:",s.data.items?s.data.items.length:0),s.data.items)for(const e of s.data.items){const t=e.snippet.resourceId.videoId;o.push({id:t,snippet:e.snippet})}n=s.data.nextPageToken,console.log(`Trovati ${o.length} video...`)}while(n);return console.log(`Totale video trovati: ${o.length}`),o}catch(e){throw console.error("Errore nel recupero video:",e.message),e}}async function getVideoDetails(e,t){const o=[],n=[];for(let e=0;e<t.length;e+=50)n.push(t.slice(e,e+50));for(let t=0;t<n.length;t++){console.log(`Recupero dettagli chunk ${t+1}/${n.length}...`);const s=await e.videos.list({id:n[t].join(","),part:"snippet,statistics,contentDetails"});s.data.items&&o.push(...s.data.items)}return o}async function main(){const e=getApiKey(),t=google.youtube({version:"v3",auth:e});console.log("YouTube BacaroTech Post Generator"),console.log("==================================\n"),console.log("Cerco il canale @Bacarotech...");const o=await getChannelInfo(t,"@Bacarotech");o||(console.error("Canale non trovato!"),process.exit(1)),console.log(`Canale trovato! Channel ID: ${o.id}`),console.log(`Uploads Playlist ID: ${o.uploadsPlaylistId}`);const n=await getAllVideos(t,o.uploadsPlaylistId);0===n.length&&(console.log("Nessun video trovato!"),process.exit(0)),console.log("\nRecupero i dettagli dei video...");const s=n.map(e=>e.id),a=await getVideoDetails(t,s),r={};for(const e of a)r[e.id]=e;console.log("\nGenerazione dei post in corso...");let i=0,l=0;for(const e of n){const t=r[e.id]||e,o=isShort(t.contentDetails?.duration),n=t.snippet.title,s=extractSeries(n);s&&console.log(`  Serie trovata: ${s} - ${n}`);const a=generateSlug(n),{frontmatter:c,year:u}=generateFrontmatter(t,o,s),p=generateContent(t,o),d=path.join(OUTPUT_DIR,String(u));fs.existsSync(d)||fs.mkdirSync(d,{recursive:!0});const g=path.join(d,a);if(fs.existsSync(g)){console.log(`  - Skip: ${n} (già esiste)`),l++;continue}fs.mkdirSync(g,{recursive:!0});const f=path.join(g,"index.md");fs.writeFileSync(f,c+p),console.log(`  + Creato: ${n}`),i++}console.log("\n=================================="),console.log("Completato!"),console.log(`  - Post creati: ${i}`),console.log(`  - Post saltati: ${l}`),console.log(`  - Directory output: ${OUTPUT_DIR}`)}main().catch(e=>{console.error("Errore:",e.message),process.exit(1)});